import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Termux Setup","description":"","frontmatter":{},"headers":[],"relativePath":"guide/termux-setup.md","filePath":"guide/termux-setup.md"}'),n={name:"guide/termux-setup.md"};function r(l,e,o,d,h,p){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="termux-setup" tabindex="-1">Termux Setup <a class="header-anchor" href="#termux-setup" aria-label="Permalink to &quot;Termux Setup&quot;">​</a></h1><p>Termux integration enables Lyra Code to execute commands, run scripts, and interact with your Android device&#39;s terminal environment.</p><h2 id="why-termux" tabindex="-1">Why Termux? <a class="header-anchor" href="#why-termux" aria-label="Permalink to &quot;Why Termux?&quot;">​</a></h2><ul><li>Execute shell commands and scripts directly from AI conversations</li><li>Run development tools (Python, Node.js, Git, etc.)</li><li>Manage files programmatically</li><li>Full Linux-like environment on Android</li></ul><h2 id="step-by-step-setup" tabindex="-1">Step-by-Step Setup <a class="header-anchor" href="#step-by-step-setup" aria-label="Permalink to &quot;Step-by-Step Setup&quot;">​</a></h2><h3 id="_1-install-termux" tabindex="-1">1. Install Termux <a class="header-anchor" href="#_1-install-termux" aria-label="Permalink to &quot;1. Install Termux&quot;">​</a></h3><p>Download and install Termux from F-Droid:</p><p>👉 <a href="https://f-droid.org/packages/com.termux/" target="_blank" rel="noreferrer">Termux on F-Droid</a></p><div class="warning custom-block"><p class="custom-block-title">Google Play Version</p><p>The Google Play version of Termux is <strong>outdated and unmaintained</strong>. Always use the F-Droid version for the latest features and security updates.</p></div><h3 id="_2-enable-external-app-calls" tabindex="-1">2. Enable External App Calls <a class="header-anchor" href="#_2-enable-external-app-calls" aria-label="Permalink to &quot;2. Enable External App Calls&quot;">​</a></h3><p>Open Termux and run the following commands:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.termux</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;allow-external-apps=true&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.termux/termux.properties</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">termux-reload-settings</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>This allows Lyra Code to communicate with Termux through its <code>RunCommandService</code>.</p><h3 id="_3-grant-permission-in-lyra-code" tabindex="-1">3. Grant Permission in Lyra Code <a class="header-anchor" href="#_3-grant-permission-in-lyra-code" aria-label="Permalink to &quot;3. Grant Permission in Lyra Code&quot;">​</a></h3><ol><li>Open <strong>Lyra Code</strong></li><li>Go to <strong>Settings → Agent</strong></li><li>Enable the <strong>Termux Communication</strong> permission</li></ol><p>If permission is not granted, the <code>run_command</code> tool is automatically disabled.</p><h3 id="_4-verify-the-setup" tabindex="-1">4. Verify the Setup <a class="header-anchor" href="#_4-verify-the-setup" aria-label="Permalink to &quot;4. Verify the Setup&quot;">​</a></h3><p>Start a new conversation in Lyra Code and ask the AI to run a simple command:</p><blockquote><p>Run: <code>echo Hello from Termux</code></p></blockquote><p>If everything works, you should see the output <code>Hello from Termux</code>.</p><h2 id="recommended-packages" tabindex="-1">Recommended Packages <a class="header-anchor" href="#recommended-packages" aria-label="Permalink to &quot;Recommended Packages&quot;">​</a></h2><p>Install these packages for the best experience:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pkg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodejs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="command-times-out" tabindex="-1">Command times out <a class="header-anchor" href="#command-times-out" aria-label="Permalink to &quot;Command times out&quot;">​</a></h3><ul><li>Check if Termux is running in the background</li><li>Disable battery optimization for Termux</li><li>Ensure Termux has notification permissions</li></ul><h3 id="permission-denied" tabindex="-1">Permission denied <a class="header-anchor" href="#permission-denied" aria-label="Permalink to &quot;Permission denied&quot;">​</a></h3><ul><li>Verify <code>allow-external-apps=true</code> is set in <code>~/.termux/termux.properties</code></li><li>Run <code>termux-reload-settings</code> after making changes</li><li>Restart Termux</li></ul><h3 id="commands-not-executing" tabindex="-1">Commands not executing <a class="header-anchor" href="#commands-not-executing" aria-label="Permalink to &quot;Commands not executing&quot;">​</a></h3><ul><li>Make sure the Termux communication permission is enabled in Lyra Code</li><li>Check that Termux is installed from F-Droid, not Google Play</li></ul><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to &quot;Security Considerations&quot;">​</a></h2><ul><li>Lyra Code&#39;s command execution requires <strong>explicit user approval</strong> for each command</li><li>Review commands before approving them</li><li>Commands run with the same permissions as the Termux user</li><li>Be cautious when running commands that modify system files or install packages</li></ul>`,32)])])}const c=a(n,[["render",r]]);export{m as __pageData,c as default};
